const body = $json.body || $json;
const inputText = String(body.input_text || body.text || '').trim();
const source = String(body.source || 'webhook').trim() || 'webhook';
const community = String(body.community || 'global').trim() || 'global';
const now = new Date();
const isoNow = now.toISOString();

return [{
  json: {
    input_text: inputText,
    original_input_text: inputText,
    source,
    community,
    received_at: String(body.received_at || isoNow),
    current_date: isoNow.slice(0, 10),
    last_updated: isoNow,
    version: '1.0',
    vault_root: '/data/vault'
  }
}];

const prefixMap = {
  '/post': { classification: 'post_order', target_folder: 'vault/03_Post_Orders' },
  '/incident': { classification: 'incident', target_folder: 'vault/06_Incidents' },
  '/qa': { classification: 'qa_rule', target_folder: 'vault/04_QA_Rules' },
  '/log': { classification: 'visitor_log', target_folder: 'vault/07_Visitor_Logs' },
  '/automation': { classification: 'automation', target_folder: 'vault/10_Automations' },
  '/workflow': { classification: 'workflow', target_folder: 'vault/10_Automations' },
  '/help': { classification: 'help_response', target_folder: '' }
};

const keywordRules = [
  { classification: 'post_order', target_folder: 'vault/03_Post_Orders', keywords: ['post order', 'must', 'required', 'before access', 'not allowed', 'physical id', 'visitor must'] },
  { classification: 'incident', target_folder: 'vault/06_Incidents', keywords: ['incident', 'tailgate', 'tailgating', 'gate arm', 'happened', 'reported'] },
  { classification: 'qa_rule', target_folder: 'vault/04_QA_Rules', keywords: ['qa', 'ding', 'audit', 'compliance'] },
  { classification: 'visitor_log', target_folder: 'vault/07_Visitor_Logs', keywords: ['tag:', 'resident:', 'visitor:', 'vendor:'] },
  { classification: 'automation', target_folder: 'vault/10_Automations', keywords: ['n8n', 'webhook', 'automation'] },
  { classification: 'workflow', target_folder: 'vault/10_Automations', keywords: ['workflow', 'process', 'step by step'] }
];

function titleCase(input) {
  return String(input || '')
    .replace(/[-_]+/g, ' ')
    .split(/\s+/)
    .filter(Boolean)
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
    .join(' ');
}

function slugify(input, maxLength = 72) {
  const slug = String(input || '')
    .toLowerCase()
    .replace(/[\\/:*?"<>|]/g, ' ')
    .replace(/[^a-z0-9\s-]/g, ' ')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-+|-+$/g, '');
  return (slug || 'untitled').slice(0, maxLength).replace(/-+$/g, '') || 'untitled';
}

function firstSentence(input) {
  const normalized = String(input || '').replace(/\s+/g, ' ').trim();
  const match = normalized.match(/^(.{1,140}?)([.!?]|$)/);
  return (match ? match[1] : normalized.slice(0, 140)).trim();
}

function classifyByKeywords(text) {
  const lower = text.toLowerCase();
  for (const rule of keywordRules) {
    if (rule.keywords.some((keyword) => lower.includes(keyword))) {
      return { classification: rule.classification, target_folder: rule.target_folder, classification_source: 'keyword' };
    }
  }
  return { classification: 'unknown', target_folder: 'vault/00_Inbox', classification_source: 'fallback' };
}

return items.map((item) => {
  const payload = item.json;
  const raw = String(payload.input_text || '').trim();
  const lower = raw.toLowerCase();
  const matchedPrefix = Object.keys(prefixMap).find((prefix) => lower === prefix || lower.startsWith(`${prefix} `));
  const command = matchedPrefix || '';
  const bodyText = matchedPrefix ? raw.slice(matchedPrefix.length).trim() : raw;
  const routed = matchedPrefix ? { ...prefixMap[matchedPrefix], classification_source: 'prefix' } : classifyByKeywords(raw);
  const highPriority = ['post_order', 'incident', 'qa_rule'];
  const humanReview = ['post_order', 'incident', 'qa_rule', 'unknown'].includes(routed.classification);
  const priority = highPriority.includes(routed.classification) ? 'high' : 'medium';
  const communitySlug = slugify(payload.community || 'global', 32);
  const topicSlug = slugify(firstSentence(bodyText || routed.classification), 64);
  const classificationSlug = slugify(routed.classification, 32);
  const filename = `${payload.current_date}-${communitySlug}-${topicSlug}-${classificationSlug}.md`;
  const title = titleCase(firstSentence(bodyText || routed.classification));
  const usage = [
    'SafePassage Phase 2 Minimal POW ingestion commands:',
    '/post <text> - route post orders to vault/03_Post_Orders',
    '/incident <text> - route incidents to vault/06_Incidents',
    '/qa <text> - route QA rules to vault/04_QA_Rules',
    '/log <text> - route visitor logs to vault/07_Visitor_Logs',
    '/automation <text> - route automations to vault/10_Automations',
    '/workflow <text> - route workflows to vault/10_Automations',
    '/help - return this usage response without writing a file'
  ];

  return {
    json: {
      ...payload,
      command,
      body_text: bodyText,
      classification: routed.classification,
      classification_source: routed.classification_source,
      target_folder: routed.target_folder,
      priority,
      human_review_required: humanReview,
      status: humanReview ? 'needs_review' : 'active',
      title,
      tags: [routed.classification, slugify(payload.community || 'global', 32), 'phase-2-minimal-pow'],
      suggested_filename: filename,
      is_help: routed.classification === 'help_response',
      help_usage: usage,
      deepseek_request_body: {
        model: 'deepseek-chat',
        temperature: 0.1,
        messages: [
          {
            role: 'system',
            content: 'Return JSON only with keys summary, details, agent_action, qa_notes, open_questions. Clean and improve Markdown body sections only. Do not generate YAML frontmatter. Do not classify, route, prioritize, name files, or invent facts.'
          },
          {
            role: 'user',
            content: JSON.stringify({
              input_text: bodyText,
              classification: routed.classification,
              community: payload.community,
              source: payload.source,
              required_schema: {
                summary: '',
                details: '',
                agent_action: '',
                qa_notes: '',
                open_questions: []
              }
            })
          }
        ]
      }
    }
  };
});

const payload = $('Code - Deterministic Classification and Routing').first().json;
const http = $input.first().json || {};

function fallbackSections(input) {
  const text = String(input || '').trim();
  return {
    summary: text ? text.slice(0, 220) : 'No source input was provided.',
    details: text || 'No details provided.',
    agent_action: payload.human_review_required ? 'Review this item before operational use.' : 'No manual action required unless local procedure says otherwise.',
    qa_notes: payload.human_review_required ? 'Human review is required by deterministic routing.' : 'No QA escalation required by deterministic routing.',
    open_questions: []
  };
}

function parseJsonText(value) {
  if (typeof value !== 'string') return null;
  const cleaned = value.trim().replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim();
  if (!cleaned) return null;
  return JSON.parse(cleaned);
}

let parsed = null;
let usedAi = false;
try {
  if (http && http.choices && http.choices[0] && http.choices[0].message) {
    parsed = parseJsonText(http.choices[0].message.content);
  } else if (typeof http.body === 'string') {
    const body = parseJsonText(http.body);
    parsed = body && body.choices ? parseJsonText(body.choices[0]?.message?.content) : body;
  } else if (http.body && typeof http.body === 'object') {
    parsed = http.body.choices ? parseJsonText(http.body.choices[0]?.message?.content) : http.body;
  }
  usedAi = parsed && typeof parsed === 'object';
} catch (error) {
  parsed = null;
}

const fallback = fallbackSections(payload.body_text);
const sections = {
  summary: String(parsed?.summary || fallback.summary).trim(),
  details: String(parsed?.details || fallback.details).trim(),
  agent_action: String(parsed?.agent_action || fallback.agent_action).trim(),
  qa_notes: String(parsed?.qa_notes || fallback.qa_notes).trim(),
  open_questions: Array.isArray(parsed?.open_questions) ? parsed.open_questions.map((item) => String(item).trim()).filter(Boolean) : fallback.open_questions
};

return [{
  json: {
    ...payload,
    ai_cleanup_used: usedAi,
    ai_cleanup_failed: !usedAi,
    markdown_sections: sections
  }
}];

function yamlValue(value) {
  const text = String(value ?? '').replace(/\r?\n/g, ' ').replace(/"/g, '\\"').trim();
  return `"${text}"`;
}

function yamlArray(values) {
  const list = Array.isArray(values) ? values : [];
  return `[${list.map((value) => yamlValue(value)).join(', ')}]`;
}

function sectionList(values) {
  if (!Array.isArray(values) || values.length === 0) return '- None recorded.';
  return values.map((value) => `- ${String(value).trim()}`).join('\n');
}

return items.map((item) => {
  const payload = item.json;
  if (payload.is_help) {
    return {
      json: {
        ...payload,
        should_write: false,
        response_status: 'ok',
        response_message: payload.help_usage.join('\n')
      }
    };
  }

  const sections = payload.markdown_sections || {};
  const markdown = [
    '---',
    `title: ${yamlValue(payload.title)}`,
    `type: ${yamlValue(payload.classification)}`,
    `community: ${yamlValue(payload.community)}`,
    `priority: ${yamlValue(payload.priority)}`,
    `effective_date: ${yamlValue(payload.current_date)}`,
    `source: ${yamlValue(payload.source)}`,
    `status: ${yamlValue(payload.status)}`,
    `tags: ${yamlArray(payload.tags)}`,
    `last_updated: ${yamlValue(payload.last_updated)}`,
    `version: ${yamlValue(payload.version)}`,
    `human_review_required: ${payload.human_review_required ? 'true' : 'false'}`,
    '---',
    '',
    `# ${payload.title}`,
    '',
    '## Summary',
    '',
    sections.summary || 'No summary available.',
    '',
    '## Details',
    '',
    sections.details || 'No details available.',
    '',
    '## Agent Action',
    '',
    sections.agent_action || 'No agent action recorded.',
    '',
    '## QA Notes',
    '',
    sections.qa_notes || 'No QA notes recorded.',
    '',
    '## Open Questions',
    '',
    sectionList(sections.open_questions),
    '',
    '## Source Input',
    '',
    payload.body_text || payload.original_input_text || 'No source input provided.',
    '',
    '## Change History',
    '',
    `- ${payload.current_date}: Created by Phase 2 Minimal POW ingestion workflow.`,
    ''
  ].join('\n');

  return {
    json: {
      ...payload,
      should_write: true,
      final_markdown: markdown
    }
  };
});

const path = require('path');
const vaultRoot = path.resolve('/data/vault');
const requiredFields = ['title', 'type', 'community', 'priority', 'effective_date', 'source', 'status', 'tags', 'last_updated', 'version', 'human_review_required'];

function validateFrontmatter(markdown) {
  const match = String(markdown || '').match(/^---\n([\s\S]*?)\n---\n/);
  if (!match) throw new Error('Final Markdown is missing YAML frontmatter.');
  for (const field of requiredFields) {
    if (!new RegExp(`^${field}:`, 'm').test(match[1])) {
      throw new Error(`Final Markdown is missing required YAML field: ${field}`);
    }
  }
}

function validateFilename(filename) {
  if (!filename || typeof filename !== 'string') throw new Error('Filename is required.');
  if (!filename.endsWith('.md')) throw new Error('Filename must end with .md.');
  if (/[\\/:*?"<>|]/.test(filename)) throw new Error('Filename contains unsafe filesystem characters.');
  if (filename.includes('..') || filename.includes(' ')) throw new Error('Filename contains path traversal or spaces.');
}

return items.map((item) => {
  const payload = item.json;
  if (!payload.should_write) {
    return { json: { ...payload, validated: true, final_destination: null } };
  }

  const targetFolder = String(payload.target_folder || '').replace(/\\/g, '/');
  if (!targetFolder.startsWith('vault/')) throw new Error('target_folder must start with vault/.');
  if (targetFolder.includes('..') || path.isAbsolute(targetFolder)) throw new Error('Unsafe target_folder blocked.');

  validateFilename(payload.suggested_filename);
  validateFrontmatter(payload.final_markdown);

  const relativeFolder = targetFolder.replace(/^vault\//, '');
  const folderPath = path.resolve(vaultRoot, relativeFolder);
  const finalDestination = path.resolve(folderPath, payload.suggested_filename);
  if (!folderPath.startsWith(`${vaultRoot}${path.sep}`) || !finalDestination.startsWith(`${vaultRoot}${path.sep}`)) {
    throw new Error('Final destination must stay inside /data/vault.');
  }

  return {
    json: {
      ...payload,
      validated: true,
      final_destination: finalDestination,
      relative_vault_path: path.posix.join(targetFolder, payload.suggested_filename)
    }
  };
});

const fs = require('fs');
const path = require('path');
const vaultRoot = path.resolve('/data/vault');

function timestamp() {
  const now = new Date();
  const hh = String(now.getHours()).padStart(2, '0');
  const mm = String(now.getMinutes()).padStart(2, '0');
  const ss = String(now.getSeconds()).padStart(2, '0');
  return `${hh}${mm}${ss}`;
}

return items.map((item) => {
  const payload = item.json;
  if (!payload.should_write) {
    return {
      json: {
        ...payload,
        write_status: 'skipped',
        written_file: null,
        written_filename: null
      }
    };
  }

  let destination = payload.final_destination;
  let filename = payload.suggested_filename;
  if (fs.existsSync(destination)) {
    filename = filename.replace(/\.md$/i, `-${timestamp()}.md`);
    destination = path.resolve(path.dirname(destination), filename);
    if (!destination.startsWith(`${vaultRoot}${path.sep}`)) throw new Error('Timestamped destination escaped /data/vault.');
  }

  fs.mkdirSync(path.dirname(destination), { recursive: true });
  fs.writeFileSync(destination, payload.final_markdown, 'utf8');

  return {
    json: {
      ...payload,
      write_status: 'written',
      written_file: destination,
      written_filename: filename,
      relative_vault_path: path.posix.join(payload.target_folder, filename)
    }
  };
});

return items.map((item) => {
  const payload = item.json;
  if (payload.is_help) {
    return {
      json: {
        status: 'ok',
        command: '/help',
        wrote_file: false,
        usage: payload.help_usage
      }
    };
  }

  return {
    json: {
      status: 'accepted',
      classification: payload.classification,
      classification_source: payload.classification_source,
      priority: payload.priority,
      target_folder: payload.target_folder,
      suggested_filename: payload.written_filename || payload.suggested_filename,
      relative_vault_path: payload.relative_vault_path,
      written_file: payload.written_file,
      human_review_required: payload.human_review_required,
      document_status: payload.status,
      ai_cleanup_used: payload.ai_cleanup_used,
      ai_cleanup_failed: payload.ai_cleanup_failed,
      write_status: payload.write_status
    }
  };
});
